enum VisibilityRule {
    /// Fixed string, no detection needed (e.g., "module-level", "default").
    Fixed(&'static str),
    /// Majority wins: count chunks where signature contains `keyword`.
    /// `(keyword, if_majority, if_minority)`.
    SigContainsMajority {
        keyword: &'static str,
        if_majority: &'static str,
        if_minority: &'static str,
    },
    /// Majority wins: count chunks where signature starts with `prefix`.
    /// `(prefix, if_majority, if_minority)`.
    SigStartsMajority {
        prefix: &'static str,
        if_majority: &'static str,
        if_minority: &'static str,
    },
    /// Two-keyword comparison: public vs internal (for .NET languages).
    /// Counts `contains(pub_kw)` vs `contains(int_kw)`.
    TwoKeywordCompare {
        pub_keyword: &'static str,
        int_keyword: &'static str,
        if_pub_wins: &'static str,
        if_int_wins: &'static str,
    },
    /// Solidity: `public || external` vs rest.
    SigContainsEitherMajority {
        keyword_a: &'static str,
        keyword_b: &'static str,
        if_majority: &'static str,
        if_minority: &'static str,
    },
}

fn post_process_perl_perl(
    name: &mut String,
    chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    source: &str,
) -> bool {
    match node.kind() {
        "function_definition" => *chunk_type = ChunkType::Function,
        "package_statement" => {
            *chunk_type = ChunkType::Module;
            // Extract package name from text: "package Foo::Bar;"
            let text = node.utf8_text(source.as_bytes()).unwrap_or("");
            let text = text.trim();
            if let Some(rest) = text.strip_prefix("package") {
                let rest = rest.trim();
                // Take until ; or { or whitespace
                let pkg_name: String = rest
                    .chars()
                    .take_while(|c| *c != ';' && *c != '{' && !c.is_whitespace())
                    .collect();
                if !pkg_name.is_empty() {
                    *name = pkg_name;
                }
            }
        }
        _ => {}
    }
    // sub new → Constructor
    if matches!(*chunk_type, ChunkType::Function | ChunkType::Method) && name == "new" {
        *chunk_type = ChunkType::Constructor;
    }
    // Test::More subtest or test_ prefix
    if matches!(*chunk_type, ChunkType::Function | ChunkType::Method) && name.starts_with("test_") {
        *chunk_type = ChunkType::Test;
    }
    true
}

fn post_process_julia_julia(
    _name: &mut String,
    chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    _source: &str,
) -> bool {
    match node.kind() {
        "function_definition" => *chunk_type = ChunkType::Function,
        "struct_definition" => *chunk_type = ChunkType::Struct,
        "abstract_definition" => *chunk_type = ChunkType::TypeAlias,
        "module_definition" => *chunk_type = ChunkType::Module,
        "macro_definition" => *chunk_type = ChunkType::Macro,
        "macrocall_expression" => {
            // @test, @testset → Test
            let node_text = &_source[node.byte_range()];
            if node_text.starts_with("@test") {
                *chunk_type = ChunkType::Test;
            }
        }
        _ => {}
    }
    // test_ prefix → Test
    if *chunk_type == ChunkType::Function && _name.starts_with("test_") {
        *chunk_type = ChunkType::Test;
    }
    // const FOO = ... → Constant
    if *chunk_type == ChunkType::Struct {
        let node_text = &_source[node.byte_range()];
        if node_text.trim_start().starts_with("const ") && !node_text.contains("struct") {
            *chunk_type = ChunkType::Constant;
        }
    }
    true
}

