enum VisibilityRule {
    /// Fixed string, no detection needed (e.g., "module-level", "default").
    Fixed(&'static str),
    /// Majority wins: count chunks where signature contains `keyword`.
    /// `(keyword, if_majority, if_minority)`.
    SigContainsMajority {
        keyword: &'static str,
        if_majority: &'static str,
        if_minority: &'static str,
    },
    /// Majority wins: count chunks where signature starts with `prefix`.
    /// `(prefix, if_majority, if_minority)`.
    SigStartsMajority {
        prefix: &'static str,
        if_majority: &'static str,
        if_minority: &'static str,
    },
    /// Two-keyword comparison: public vs internal (for .NET languages).
    /// Counts `contains(pub_kw)` vs `contains(int_kw)`.
    TwoKeywordCompare {
        pub_keyword: &'static str,
        int_keyword: &'static str,
        if_pub_wins: &'static str,
        if_int_wins: &'static str,
    },
    /// Solidity: `public || external` vs rest.
    SigContainsEitherMajority {
        keyword_a: &'static str,
        keyword_b: &'static str,
        if_majority: &'static str,
        if_minority: &'static str,
    },
}

async fn migrate_v19_to_v20(conn: &mut sqlx::SqliteConnection) -> Result<(), StoreError> {
    let _span = tracing::info_span!("migrate_v19_to_v20").entered();

    sqlx::query(
        "CREATE TRIGGER IF NOT EXISTS bump_splade_on_chunks_delete \
         AFTER DELETE ON chunks \
         BEGIN \
             INSERT INTO metadata (key, value) VALUES ('splade_generation', '1') \
             ON CONFLICT(key) DO UPDATE SET \
                 value = CAST((CAST(value AS INTEGER) + 1) AS TEXT); \
         END",
    )
    .execute(&mut *conn)
    .await?;

    // Bump generation immediately so any pre-v20 persisted splade.index.bin
    // (possibly already out of sync with sparse_vectors because watch-mode
    // deletes since v19 landed never bumped the counter) gets invalidated
    // on the next load.
    sqlx::query(
        "INSERT INTO metadata (key, value) VALUES ('splade_generation', '1')
         ON CONFLICT(key) DO UPDATE SET
             value = CAST((CAST(value AS INTEGER) + 1) AS TEXT)",
    )
    .execute(&mut *conn)
    .await?;

    tracing::info!(
        "Migrated to v20: AFTER DELETE trigger on chunks bumps splade_generation (DS-W2/OB-22 fix)"
    );
    Ok(())
}

impl LlmClient {
    /// Creates a new LLM client instance with the specified API key and configuration.
    ///
    /// Initializes an HTTP client with a 60-second timeout and disables automatic redirect following. The API key is stored for use in subsequent requests.
    ///
    /// # Arguments
    ///
    /// * `api_key` - The API key for authenticating requests to the LLM service
    /// * `llm_config` - Configuration settings for the LLM client behavior
    ///
    /// # Returns
    ///
    /// A new `Self` instance ready to make LLM requests, or an `LlmError` if the HTTP client initialization fails.
    ///
    /// # Errors
    ///
    /// Returns an error if the underlying HTTP client cannot be constructed.
    pub fn new(api_key: &str, llm_config: LlmConfig) -> Result<Self, LlmError> {
        Ok(Self {
            http: reqwest::blocking::Client::builder()
                .timeout(Duration::from_secs(60))
                .redirect(reqwest::redirect::Policy::none())
                .build()?,
            api_key: api_key.to_string(),
            llm_config,
        })
    }
}

