pub fn get_ref(&self, name: &str) -> Result<()> {
        let _span = tracing::info_span!("batch_get_ref", %name).entered();
        {
            let mut refs = self.refs.borrow_mut();
            if let Some(existing) = refs.peek(name) {
                if existing.is_stale() {
                    tracing::info!(
                        reference = %name,
                        "Cached reference stale (index.db mtime/size changed) — evicting for reload"
                    );
                    refs.pop(name);
                } else {
                    return Ok(());
                }
            }
        }

        let config = self.config();
        // Filter to just the target reference instead of loading all (RM-16)
        let single: Vec<_> = config
            .references
            .iter()
            .filter(|r| r.name == name)
            .cloned()
            .collect();
        if single.is_empty() {
            anyhow::bail!(
                "Reference '{}' not found. Run 'cqs ref list' to see available references.",
                name
            );
        }
        let loaded = cqs::reference::load_references(&single);
        let found = loaded.into_iter().next().ok_or_else(|| {
            anyhow::anyhow!(
                "Failed to load reference '{}'. Run 'cqs ref update {}' first.",
                name,
                name
            )
        })?;
        self.refs.borrow_mut().put(name.to_string(), found);
        Ok(())
    }

impl ReferenceIndex {
    /// RM-V1.25-7: Has the reference's `index.db` been rewritten since load?
    ///
    /// Returns `true` when the current (mtime, size) differs from the value
    /// captured at construction. If we couldn't read the file at all (or
    /// had no identity at load time), returns `false` so the caller keeps
    /// using the cached index — transient NFS/permission glitches shouldn't
    /// thrash the LRU.
    pub fn is_stale(&self) -> bool {
        let Some(loaded) = self.loaded_identity else {
            return false;
        };
        let Some(current) = stat_identity(&self.db_path) else {
            return false;
        };
        current != loaded
    }
}

