fn rerank_unified(
    reranker: &cqs::Reranker,
    query: &str,
    results: Vec<UnifiedResult>,
    limit: usize,
) -> Result<Vec<UnifiedResult>> {
    let mut code_results: Vec<cqs::store::SearchResult> = results
        .into_iter()
        .map(|r| match r {
            UnifiedResult::Code(sr) => sr,
        })
        .collect();

    if code_results.len() > 1 {
        reranker
            .rerank(query, &mut code_results, limit)
            .map_err(|e| anyhow::anyhow!("Reranking failed: {e}"))?;
    }

    Ok(code_results.into_iter().map(UnifiedResult::Code).collect())
}

pub(crate) fn mmr_rerank(candidates: &[MmrCandidate<'_>], limit: usize, lambda: f32) -> Vec<usize> {
    let lambda = lambda.clamp(0.0, 1.0);
    let n = candidates.len();
    let limit = limit.min(n);

    if limit == 0 {
        return Vec::new();
    }
    if lambda >= 1.0 || n <= limit {
        return (0..limit).collect();
    }

    let mut selected: Vec<usize> = Vec::with_capacity(limit);
    let mut selected_mask = vec![false; n];

    while selected.len() < limit {
        let mut best_idx = usize::MAX;
        let mut best_mmr = f32::NEG_INFINITY;

        for (i, cand) in candidates.iter().enumerate() {
            if selected_mask[i] {
                continue;
            }

            let max_sim = if selected.is_empty() {
                0.0
            } else {
                selected
                    .iter()
                    .map(|&j| similarity(cand, &candidates[j]))
                    .fold(0.0f32, f32::max)
            };

            let mmr = lambda * cand.score - (1.0 - lambda) * max_sim;
            // Tie-break on score (then implicit input-order via i ordering)
            // so the result is deterministic across runs.
            if mmr > best_mmr || (mmr == best_mmr && best_idx == usize::MAX) {
                best_mmr = mmr;
                best_idx = i;
            }
        }

        if best_idx == usize::MAX {
            break;
        }
        selected_mask[best_idx] = true;
        selected.push(best_idx);
    }

    selected
}

pub(crate) fn apply_scoring_pipeline(
    embedding_score: f32,
    name: Option<&str>,
    file_part: &str,
    ctx: &ScoringContext<'_>,
) -> Option<f32> {
    let base_score = if let Some(matcher) = ctx.name_matcher {
        let n = name.unwrap_or("");
        let name_score = matcher.score(n);
        (1.0 - ctx.filter.name_boost) * embedding_score + ctx.filter.name_boost * name_score
    } else {
        embedding_score
    };

    if let Some(matcher) = ctx.glob_matcher {
        if !matcher.is_match(file_part) {
            return None;
        }
    }

    let chunk_name = name.unwrap_or("");
    let mut score = base_score.max(0.0) * ctx.note_index.boost(file_part, chunk_name);

    if ctx.filter.enable_demotion {
        score *= chunk_importance(chunk_name, file_part);
    }

    if score >= ctx.threshold {
        Some(score)
    } else {
        None
    }
}

