pub(super) fn make_chunk(name: &str, file: &str) -> Chunk {
        let content = format!("fn {}() {{ /* body */ }}", name);
        let hash = blake3::hash(content.as_bytes()).to_hex().to_string();
        Chunk {
            id: format!("{}:1:{}", file, &hash[..8]),
            file: PathBuf::from(file),
            language: Language::Rust,
            chunk_type: ChunkType::Function,
            name: name.to_string(),
            signature: format!("fn {}()", name),
            content,
            doc: None,
            line_start: 1,
            line_end: 5,
            content_hash: hash,
            parent_id: None,
            window_idx: None,
            parent_type_name: None,
        }
    }

fn post_process_powershell_powershell(
    name: &mut String,
    chunk_type: &mut ChunkType,
    _node: tree_sitter::Node,
    _source: &str,
) -> bool {
    // Pester: Describe/It/Context blocks → Test
    if matches!(*chunk_type, ChunkType::Function | ChunkType::Method)
        && (name == "Describe" || name == "It" || name == "Context" || name.starts_with("Test"))
    {
        *chunk_type = ChunkType::Test;
    }
    true
}

fn post_process_r_r(
    name: &mut String,
    chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    source: &str,
) -> bool {
    match *chunk_type {
        ChunkType::Class => {
            // This is a top-level `call` node captured by @class.
            // Only keep S4 class-defining calls; extract class name from first string arg.
            if !S4_CLASS_FUNCTIONS_R.contains(&name.as_str()) {
                return false;
            }
            if let Some(class_name) = first_string_arg_r(node, source) {
                *name = class_name.to_string();
                true
            } else {
                // Can't extract class name — discard
                false
            }
        }
        ChunkType::Constant => {
            // This is a binary_operator with non-function rhs.
            // Could be R6Class assignment or a constant.
            if is_inside_function_r(node) {
                return false;
            }

            // Check if rhs is a call to R6Class
            let rhs = node.child_by_field_name("rhs");
            if let Some(rhs_node) = rhs {
                if rhs_node.kind() == "call" {
                    if let Some(fn_name) = call_function_name_r(rhs_node, source) {
                        if fn_name == "R6Class" {
                            *chunk_type = ChunkType::Class;
                            return true;
                        }
                    }
                }
            }

            // Not R6 — UPPER_CASE stays Constant, lowercase → Variable
            if !is_upper_snake_case_r(name) {
                *chunk_type = ChunkType::Variable;
            }
            true
        }
        _ => true,
    }
}

fn post_process_haskell_haskell(
    _name: &mut String,
    chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    _source: &str,
) -> bool {
    match node.kind() {
        "function" => *chunk_type = ChunkType::Function,
        "data_type" => *chunk_type = ChunkType::Enum,
        "newtype" => *chunk_type = ChunkType::Struct,
        "type_synomym" => *chunk_type = ChunkType::TypeAlias,
        "class" => *chunk_type = ChunkType::Trait,
        "instance" => *chunk_type = ChunkType::Impl,
        _ => {}
    }
    true
}

fn post_process_bash_bash(
    _name: &mut String,
    chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    _source: &str,
) -> bool {
    // Skip export/declare inside function bodies — only capture top-level
    if *chunk_type == ChunkType::Variable {
        let mut parent = node.parent();
        while let Some(p) = parent {
            if p.kind() == "function_definition" {
                return false;
            }
            parent = p.parent();
        }
    }
    true
}

fn post_process_fsharp_fsharp(
    name: &mut String,
    chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    source: &str,
) -> bool {
    // [<Test>], [<Fact>], [<Theory>] attributes → Test
    if matches!(*chunk_type, ChunkType::Function | ChunkType::Method) {
        // Check preceding siblings for attribute lists
        let mut prev = node.prev_named_sibling();
        while let Some(sib) = prev {
            let sib_text = &source[sib.byte_range()];
            if sib_text.starts_with("[<") {
                if sib_text.contains("Test")
                    || sib_text.contains("Fact")
                    || sib_text.contains("Theory")
                {
                    *chunk_type = ChunkType::Test;
                    return true;
                }
            } else {
                break;
            }
            prev = sib.prev_named_sibling();
        }
        // Also check first line of node text
        let node_text = &source[node.byte_range()];
        let header = &node_text[..node_text.floor_char_boundary(200)];
        if header.contains("[<Test>]")
            || header.contains("[<Fact>]")
            || header.contains("[<Theory>]")
        {
            *chunk_type = ChunkType::Test;
        }
    }
    let _ = name;
    true
}

fn post_process_cpp_cpp(
    name: &mut String,
    chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    _source: &str,
) -> bool {
    if !matches!(*chunk_type, ChunkType::Function | ChunkType::Method) {
        return true;
    }
    // Skip destructors
    if name.starts_with('~') {
        return true;
    }
    // C++ constructors: function_definition with no return type before the declarator.
    if node.kind() == "function_definition" {
        let has_return_type = node.child_by_field_name("type").is_some();
        if !has_return_type {
            *chunk_type = ChunkType::Constructor;
        }
    }
    // extern "C" { } → Extern (walk parents for linkage_specification)
    let mut parent = node.parent();
    while let Some(p) = parent {
        if p.kind() == "linkage_specification" {
            *chunk_type = ChunkType::Extern;
            break;
        }
        if p.kind() == "translation_unit" {
            break;
        }
        parent = p.parent();
    }
    true
}

fn infer_chunk_type(
    node: tree_sitter::Node,
    language: Language,
    source: &str,
) -> (ChunkType, Option<String>) {
    let def = language.def();

    // Check if the node itself is a method kind (e.g., Go's "method_declaration")
    if def.method_node_kinds.contains(&node.kind()) {
        let parent_type = extract_method_receiver_type(node, language, source);
        return (ChunkType::Method, parent_type);
    }

    // Check if the function has a qualified name (e.g., C++ out-of-class methods)
    if let Some(extractor) = def.extract_qualified_method {
        if let Some(class_name) = extractor(node, source) {
            tracing::debug!(class = %class_name, "Qualified method inference");
            return (ChunkType::Method, Some(class_name));
        }
    }

    // Walk parents looking for method containers (e.g., impl blocks, class bodies)
    let mut current = node.parent();
    while let Some(parent) = current {
        if def.method_containers.contains(&parent.kind()) {
            let parent_type = extract_container_type_name(parent, language, source);
            return (ChunkType::Method, parent_type);
        }
        current = parent.parent();
    }

    (ChunkType::Function, None)
}

fn make_chunk(name: &str, file: &str, lang: Language) -> Chunk {
        let content = format!("fn {}() {{ /* body */ }}", name);
        let hash = blake3::hash(content.as_bytes()).to_hex().to_string();
        Chunk {
            id: format!("{}:1:{}", file, &hash[..8]),
            file: PathBuf::from(file),
            language: lang,
            chunk_type: ChunkType::Function,
            name: name.to_string(),
            signature: format!("fn {}()", name),
            content,
            doc: None,
            line_start: 1,
            line_end: 5,
            content_hash: hash,
            parent_id: None,
            window_idx: None,
            parent_type_name: None,
        }
    }

