pub(crate) struct ScoringContext<'a> {
    pub query: &'a [f32],
    pub filter: &'a SearchFilter,
    pub name_matcher: Option<&'a NameMatcher>,
    pub glob_matcher: Option<&'a globset::GlobMatcher>,
    /// PF-V1.25-4: accepts either a freshly-built `NoteBoostIndex` borrowing
    /// from per-call notes, or a cached `Arc<OwnedNoteBoostIndex>` reused
    /// across searches. The `NoteBoost` enum dispatches at the call site.
    pub note_index: &'a super::note_boost::NoteBoost<'a>,
    pub threshold: f32,
}

impl ScoringConfig {
    pub const DEFAULT: Self = Self {
        name_exact: 1.0,
        name_contains: 0.8,
        name_contained_by: 0.6,
        name_max_overlap: 0.5,
        note_boost_factor: 0.15,
        importance_test: 0.70,
        importance_private: 0.80,
        parent_boost_per_child: 0.05,
        parent_boost_cap: 1.15,
    };

    // CQ-7: `with_overrides` removed — was dead code (`#[allow(dead_code)]`).
    // Scoring overrides from `[scoring]` in config are applied per-field where needed
    // (e.g., `rrf_k` via `set_rrf_k_from_config`). If full config-driven scoring is
    // added later, re-introduce this method with actual production callers.
}

