fn call_function_name_r<'a>(node: tree_sitter::Node, source: &'a str) -> Option<&'a str> {
    let func = node.child_by_field_name("function")?;
    if func.kind() == "identifier" {
        return Some(&source[func.byte_range()]);
    }
    // Also handle namespaced: R6::R6Class
    if func.kind() == "namespace_operator" {
        let mut cursor = func.walk();
        if cursor.goto_first_child() {
            loop {
                let child = cursor.node();
                if child.is_named() && child.kind() == "identifier" {
                    // Take the last identifier (rhs of ::)
                    let text = &source[child.byte_range()];
                    // Keep going to find the rhs
                    if !cursor.goto_next_sibling() {
                        return Some(text);
                    }
                    // Skip :: operator
                    loop {
                        let next = cursor.node();
                        if next.is_named() && next.kind() == "identifier" {
                            return Some(&source[next.byte_range()]);
                        }
                        if !cursor.goto_next_sibling() {
                            break;
                        }
                    }
                    return Some(text);
                }
                if !cursor.goto_next_sibling() {
                    break;
                }
            }
        }
    }
    None
}

fn enrichment_nl_filters_high_freq_callees() {
        let chunk = test_chunk("my_func");
        let ctx = CallContext {
            callers: vec!["caller_a".to_string()],
            callees: vec![
                "log".to_string(),
                "rare_fn".to_string(),
                "unwrap".to_string(),
            ],
        };
        // "log" at 15%, "unwrap" at 12% — both above 10% threshold
        let mut freq = std::collections::HashMap::new();
        freq.insert("log".to_string(), 0.15);
        freq.insert("unwrap".to_string(), 0.12);
        freq.insert("rare_fn".to_string(), 0.02);

        let nl = generate_nl_with_call_context_and_summary(&chunk, &ctx, &freq, 5, 5, None, None);

        // High-frequency callees should be filtered
        assert!(
            !nl.contains("log"),
            "High-freq callee 'log' (15%) must be filtered, got: {nl}"
        );
        assert!(
            !nl.contains("unwrap"),
            "High-freq callee 'unwrap' (12%) must be filtered, got: {nl}"
        );
        // Low-frequency callee should be kept
        assert!(
            nl.contains("rare fn"),
            "Low-freq callee 'rare_fn' (2%) should be kept, got: {nl}"
        );
    }

