pub(super) fn make_chunk(name: &str, file: &str) -> Chunk {
        let content = format!("fn {}() {{ /* body */ }}", name);
        let hash = blake3::hash(content.as_bytes()).to_hex().to_string();
        Chunk {
            id: format!("{}:1:{}", file, &hash[..8]),
            file: PathBuf::from(file),
            language: Language::Rust,
            chunk_type: ChunkType::Function,
            name: name.to_string(),
            signature: format!("fn {}()", name),
            content,
            doc: None,
            line_start: 1,
            line_end: 5,
            content_hash: hash,
            parent_id: None,
            window_idx: None,
            parent_type_name: None,
        }
    }

fn post_process_json_json(
    _name: &mut String,
    _chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    _source: &str,
) -> bool {
    // pair > object > document
    if let Some(parent) = node.parent() {
        if parent.kind() == "object" {
            if let Some(grandparent) = parent.parent() {
                return grandparent.kind() == "document";
            }
        }
    }
    false
}

impl From<&ChunkSummary> for Chunk {
    fn from(cs: &ChunkSummary) -> Self {
        Self {
            id: cs.id.clone(),
            file: cs.file.clone(),
            language: cs.language,
            chunk_type: cs.chunk_type,
            name: cs.name.clone(),
            signature: cs.signature.clone(),
            content: cs.content.clone(),
            doc: cs.doc.clone(),
            line_start: cs.line_start,
            line_end: cs.line_end,
            content_hash: cs.content_hash.clone(),
            parent_id: cs.parent_id.clone(),
            window_idx: cs.window_idx.map(|i| i as u32),
            parent_type_name: cs.parent_type_name.clone(),
        }
    }
}

