pub(crate) fn get_call_query(
        &self,
        language: Language,
    ) -> Result<&tree_sitter::Query, ParserError> {
        let cell = self.call_queries.get(&language).ok_or_else(|| {
            ParserError::QueryCompileFailed(format!("{}_calls", language), "not found".into())
        })?;

        cell.get_or_try_init(|| {
            let grammar = language.try_grammar().ok_or_else(|| {
                ParserError::QueryCompileFailed(
                    format!("{}_calls", language),
                    "no tree-sitter grammar".into(),
                )
            })?;
            let pattern = language.call_query_pattern();
            tree_sitter::Query::new(&grammar, pattern).map_err(|e| {
                ParserError::QueryCompileFailed(format!("{}_calls", language), format!("{}", e))
            })
        })
    }

pub fn compute_hints_batch(
    graph: &CallGraph,
    test_chunks: &[crate::store::ChunkSummary],
    names: &[&str],
    caller_counts: &std::collections::HashMap<String, u64>,
) -> Vec<FunctionHints> {
    let _span = tracing::info_span!("compute_hints_batch", count = names.len()).entered();
    let test_names: Vec<&str> = test_chunks.iter().map(|t| t.name.as_str()).collect();
    let reachability = test_reachability(graph, &test_names, DEFAULT_MAX_TEST_SEARCH_DEPTH);

    names
        .iter()
        .map(|&name| {
            let caller_count = caller_counts
                .get(name)
                .map(|&c| c as usize)
                .unwrap_or_else(|| graph.reverse.get(name).map(|v| v.len()).unwrap_or(0));
            let test_count = reachability.get(name).copied().unwrap_or(0);
            FunctionHints {
                caller_count,
                test_count,
            }
        })
        .collect()
}

